"use client";

import * as React from "react";
import { api, MonitoringAlert, MonitoringHealth } from "@/lib/api";
import { useEnv } from "@/components/env-provider";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { cn } from "@/lib/utils";

function formatMaybeNumber(value: unknown, digits = 2): string {
  const n = typeof value === "number" ? value : Number(value);
  if (Number.isFinite(n)) return n.toFixed(digits);
  return "—";
}

export default function MonitoringPage() {
  const { connectionState, connectionText } = useEnv();

  const [health, setHealth] = React.useState<MonitoringHealth | null>(null);
  const [alerts, setAlerts] = React.useState<MonitoringAlert[] | null>(null);
  const [metricsText, setMetricsText] = React.useState<string | null>(null);
  const [loading, setLoading] = React.useState(true);
  const [error, setError] = React.useState<string>("");

  const refresh = React.useCallback(async () => {
    setError("");
    setLoading(true);
    try {
      const [h, a, m] = await Promise.all([
        api.getMonitoringHealth(),
        api.getMonitoringAlerts(),
        api.getPrometheusMetrics(),
      ]);
      setHealth(h);
      setAlerts(a);
      setMetricsText(m);
    } catch (e) {
      setError(e instanceof Error ? e.message : "Failed to fetch monitoring data.");
    } finally {
      setLoading(false);
    }
  }, []);

  React.useEffect(() => {
    const timeout = setTimeout(() => {
      void refresh();
    }, 0);
    return () => clearTimeout(timeout);
  }, [refresh]);

  const monitoringEnabled = health !== null || alerts !== null || metricsText !== null;

  return (
    <div className="flex-1 space-y-6 p-8 max-w-5xl">
      <div className="flex items-start justify-between gap-4">
        <div>
          <h1 className="text-3xl font-bold tracking-tight text-glow">Observability</h1>
          <p className="text-muted-foreground mt-1">
            Real-time infrastructure health and Prometheus telemetry.
          </p>
        </div>
        <div className="flex items-center gap-3">
          <Badge variant="outline">
            {connectionState === "connected" ? "Connected" : connectionState === "checking" ? "Checking" : "Disconnected"}
          </Badge>
          <Badge variant="outline" className="max-w-[28rem] truncate">
            {connectionText}
          </Badge>
          <Button variant="outline" onClick={refresh} disabled={loading}>
            Refresh
          </Button>
        </div>
      </div>

      {error ? (
        <div className="rounded-lg border border-border/50 bg-card/50 px-4 py-3 text-sm text-destructive">
          {error}
        </div>
      ) : null}

      <Card className="glassy-card">
        <CardHeader>
          <CardTitle className="flex items-center justify-between">
            <div className="flex items-center gap-2">
               <div className={cn("w-2 h-2 rounded-full", monitoringEnabled ? "bg-green-500 animate-pulse" : "bg-destructive")} />
               Platform Status
            </div>
            <Badge variant={monitoringEnabled ? "default" : "secondary"} className={monitoringEnabled ? "bg-green-500/20 text-green-500 border-green-500/30" : ""}>
              {monitoringEnabled ? "Healthy" : "Degraded"}
            </Badge>
          </CardTitle>
          <CardDescription>
            High-level overview of system telemtry and connected services.
          </CardDescription>
        </CardHeader>
        <CardContent className="text-sm">
          {health ? (
            <div className="grid gap-6 md:grid-cols-2 lg:grid-cols-4">
              <div className="space-y-1">
                <span className="text-xs text-muted-foreground uppercase tracking-wider font-bold">System State</span>
                <p className="text-xl font-bold text-primary">{health.status === "healthy" ? "Operational" : health.status}</p>
                <p className="text-[10px] text-muted-foreground">All core services online.</p>
              </div>
              <div className="space-y-1">
                <span className="text-xs text-muted-foreground uppercase tracking-wider font-bold">Uptime</span>
                <p className="text-xl font-bold">{health.uptime_seconds}s</p>
                <p className="text-[10px] text-muted-foreground">Time since last restart.</p>
              </div>
              <div className="space-y-1">
                <span className="text-xs text-muted-foreground uppercase tracking-wider font-bold">Incident Alerts</span>
                <p className="text-xl font-bold">{health.alerts_enabled ? "Active" : "Disabled"}</p>
                <p className="text-[10px] text-muted-foreground">Automated incident routing.</p>
              </div>
              <div className="space-y-1">
                <span className="text-xs text-muted-foreground uppercase tracking-wider font-bold">Telemetry</span>
                <p className="text-xl font-bold">{health.prometheus_enabled ? "Streaming" : "Offline"}</p>
                <p className="text-[10px] text-muted-foreground">Live infrastructure monitoring.</p>
              </div>
            </div>
          ) : (
            <div className="text-muted-foreground py-8 text-center flex flex-col items-center justify-center border border-dashed border-border/50 rounded-lg">
              {loading ? "Establishing telemetry link…" : "Observability endpoint is unreachable. Please verify environment configuration."}
            </div>
          )}
        </CardContent>
      </Card>

      <Card className="glassy-card">
        <CardHeader>
          <CardTitle>Incident Center</CardTitle>
          <CardDescription>Real-time autonomous anomaly and alert tracking.</CardDescription>
        </CardHeader>
        <CardContent>
          {alerts === null ? (
            <div className="text-sm text-muted-foreground border border-dashed border-border/50 rounded-lg py-8 text-center">
              {loading ? "Syncing incident logs…" : "Alert routing is offline."}
            </div>
          ) : alerts.length === 0 ? (
            <div className="text-sm text-green-500/80 bg-green-500/10 border border-green-500/20 rounded-lg p-6 flex flex-col items-center justify-center">
               <div className="w-10 h-10 rounded-full bg-green-500/20 flex items-center justify-center mb-3">
                  <div className="w-4 h-4 rounded-full bg-green-500" />
               </div>
               <span className="font-medium text-green-400">Zero Active Incidents</span>
               <span className="text-xs mt-1 opacity-80">All systems are operating within safe parameters.</span>
            </div>
          ) : (
            <div className="space-y-3">
              {alerts.map((a, i) => (
                <div key={i} className="rounded-lg border border-destructive/30 bg-destructive/5 px-4 py-3 text-sm transition-all hover:bg-destructive/10">
                  <div className="flex items-center justify-between gap-3">
                    <div className="font-medium truncate text-destructive">
                      {String(a.message ?? a.type ?? "Alert")}
                    </div>
                    <Badge variant="destructive" className="shrink-0 animate-pulse">
                      {String(a.severity ?? "CRITICAL")}
                    </Badge>
                  </div>
                  {a.details ? (
                    <pre className="mt-3 whitespace-pre-wrap break-words text-[10px] text-muted-foreground bg-background/50 p-2 rounded border border-border/50 font-mono">
                      {JSON.stringify(a.details, null, 2)}
                    </pre>
                  ) : null}
                </div>
              ))}
            </div>
          )}
        </CardContent>
      </Card>

      <Card className="glassy-card">
        <CardHeader>
          <CardTitle>Live Metrics Stream</CardTitle>
          <CardDescription>Raw telemetry exposed for Prometheus ingestion.</CardDescription>
        </CardHeader>
        <CardContent>
          {metricsText === null ? (
            <div className="text-sm text-muted-foreground border border-dashed border-border/50 rounded-lg py-8 text-center">
              {loading ? "Buffering metrics…" : "Metrics ingestion is currently unavailable."}
            </div>
          ) : (
            <div className="space-y-4">
              {health?.current_metrics ? (
                <div className="grid gap-4 md:grid-cols-2 text-sm bg-primary/5 border border-primary/20 rounded-lg p-4">
                  <div className="flex items-center justify-between">
                    <span className="text-muted-foreground font-medium">Error Rate Deficit</span>
                    <span className="font-mono text-primary font-bold">{formatMaybeNumber(health.current_metrics.error_rate, 4)}</span>
                  </div>
                  <div className="flex items-center justify-between border-l border-primary/20 pl-4">
                    <span className="text-muted-foreground font-medium">P99 Latency Profile</span>
                    <span className="font-mono text-primary font-bold">{formatMaybeNumber(health.current_metrics.latency_p99_ms, 1)} ms</span>
                  </div>
                </div>
              ) : null}
              <pre className="max-h-[400px] overflow-auto rounded-lg border border-border/30 bg-background/50 p-4 text-[10px] leading-relaxed custom-scrollbar font-mono text-muted-foreground">
                {metricsText}
              </pre>
            </div>
          )}
        </CardContent>
      </Card>
    </div>
  );
}

